function limitarCampo(campo,min,max){
  let valor=parseFloat(campo.value);

  if(isNaN(valor)) return;

  if(valor<min){
    campo.value=min;
  }

  if(valor>max){
    campo.value=max;
  }
}

function iniciarParticulas(){
  const c=document.getElementById("particles"),ctx=c.getContext("2d");
  const mouse={x:null,y:null,ativo:false};
  const clique={x:null,y:null,ativo:false,forca:0};
  let contadorFrame = 0;

  function ajustar(){
    c.width=innerWidth;
    c.height=innerHeight;
  }

  ajustar();
  addEventListener("resize",ajustar);

  function estaNoFundo(){
    if(mouse.x===null || mouse.y===null) return false;
    const el=document.elementFromPoint(mouse.x,mouse.y);
    if(!el) return true;
    return !el.closest("header,.card,#easterEggCNA,button,input,select,table");
  }

  addEventListener("mousemove",e=>{
    mouse.x=e.clientX;
    mouse.y=e.clientY;
    mouse.ativo=estaNoFundo();
  });

  addEventListener("click",e=>{
    mouse.x=e.clientX;
    mouse.y=e.clientY;

    if(!estaNoFundo()) return;

    clique.x=e.clientX;
    clique.y=e.clientY;
    clique.ativo=true;
    clique.forca=1;

    // aproxima as letras/símbolos conectados ao clique
    for(const p of ps){
      const dx=clique.x-p.x;
      const dy=clique.y-p.y;
      const dist=Math.sqrt(dx*dx+dy*dy);

      if(dist<170 && dist>8){
        const intensidade=(170-dist)/170;
        p.vx += dx/dist*(1.1*intensidade);
        p.vy += dy/dist*(1.1*intensidade);
        p.brilho=1;
      }
    }
  });

  addEventListener("mouseleave",()=>{mouse.ativo=false});

  const simbolos=["0","1","∂","Δ","D","P","n","i","x","t"];
  const quantidade = window.innerWidth < 800 ? 30 : 45;

  const ps=Array.from({length:quantidade},()=>({
    x:Math.random()*c.width,
    y:Math.random()*c.height,
    vx:(Math.random()-.5)*0.35,
    vy:(Math.random()-.5)*0.35,
    txt:simbolos[Math.floor(Math.random()*simbolos.length)],
    tamanho:Math.floor(Math.random()*6)+12,
    brilho:0
  }));

  function animar(){
    contadorFrame++;
    ctx.clearRect(0,0,c.width,c.height);

    if(clique.ativo){
      clique.forca*=0.90;
      if(clique.forca<0.03) clique.ativo=false;
    }

    for(const p of ps){
      if(mouse.ativo && mouse.x!==null){
        const dx=mouse.x-p.x;
        const dy=mouse.y-p.y;
        const dist=Math.sqrt(dx*dx+dy*dy);

        if(dist<145 && dist>15){
          p.vx += dx/dist*0.0055;
          p.vy += dy/dist*0.0055;
          p.brilho = Math.max(p.brilho,0.8);
        }

        if(dist<50 && dist>5){
          p.vx -= dx/dist*0.010;
          p.vy -= dy/dist*0.010;
        }
      }

      if(clique.ativo && clique.x!==null){
        const dx=clique.x-p.x;
        const dy=clique.y-p.y;
        const dist=Math.sqrt(dx*dx+dy*dy);

        if(dist<150 && dist>8){
          const intensidade=(150-dist)/150;
          p.vx += dx/dist*(0.018*clique.forca*intensidade);
          p.vy += dy/dist*(0.018*clique.forca*intensidade);
          p.brilho=Math.max(p.brilho,clique.forca);
        }
      }

      p.vx*=0.984;
      p.vy*=0.984;

      p.x+=p.vx;
      p.y+=p.vy;

      if(p.x<0 || p.x>c.width) p.vx*=-1;
      if(p.y<0 || p.y>c.height) p.vy*=-1;

      p.x=Math.max(0,Math.min(c.width,p.x));
      p.y=Math.max(0,Math.min(c.height,p.y));

      p.brilho*=0.90;

      ctx.font=p.tamanho+"px Arial";

      if(p.brilho>0.15){
        ctx.shadowColor="rgba(56,189,248,.9)";
        ctx.shadowBlur=12;
        ctx.fillStyle="rgba(210,245,255,.95)";
      }else{
        ctx.shadowBlur=0;
        ctx.fillStyle="rgba(186,230,253,.55)";
      }

      ctx.fillText(p.txt,p.x,p.y);
      ctx.shadowBlur=0;
    }

    if(contadorFrame % 2 === 0){
      for(let i=0;i<ps.length;i++){
        for(let j=i+1;j<ps.length;j+=3){
          const a=ps[i],b=ps[j];
          const dx=a.x-b.x;
          const dy=a.y-b.y;
          const dist=Math.sqrt(dx*dx+dy*dy);

          if(dist<105){
            const brilho=Math.max(a.brilho,b.brilho);
            const alpha=brilho>0.15 ? 0.40-dist/320 : 0.08-dist/700;

            ctx.strokeStyle=`rgba(56,189,248,${Math.max(alpha,0.02)})`;
            ctx.lineWidth=brilho>0.15 ? 1.4 : 0.8;

            if(brilho>0.15){
              ctx.shadowColor="rgba(56,189,248,.8)";
              ctx.shadowBlur=8;
            }

            ctx.beginPath();
            ctx.moveTo(a.x,a.y);
            ctx.lineTo(b.x,b.y);
            ctx.stroke();
            ctx.shadowBlur=0;
          }
        }
      }
    }

    if(mouse.ativo && mouse.x!==null){
      let ligacoes=0;

      for(const p of ps){
        const dx=mouse.x-p.x;
        const dy=mouse.y-p.y;
        const dist=Math.sqrt(dx*dx+dy*dy);

        if(dist<165 && ligacoes<8){
          const alpha=Math.max(0.10,0.55-dist/300);

          ctx.strokeStyle=`rgba(56,189,248,${alpha})`;
          ctx.lineWidth=1.3;
          ctx.shadowColor="rgba(56,189,248,.8)";
          ctx.shadowBlur=10;

          ctx.beginPath();
          ctx.moveTo(mouse.x,mouse.y);
          ctx.lineTo(p.x,p.y);
          ctx.stroke();
          ctx.shadowBlur=0;

          ligacoes++;
        }
      }

      ctx.beginPath();
      ctx.arc(mouse.x,mouse.y,9,0,Math.PI*2);
      ctx.strokeStyle="rgba(56,189,248,.65)";
      ctx.lineWidth=1.5;
      ctx.shadowColor="rgba(56,189,248,.8)";
      ctx.shadowBlur=12;
      ctx.stroke();
      ctx.shadowBlur=0;

      ctx.beginPath();
      ctx.arc(mouse.x,mouse.y,3.5,0,Math.PI*2);
      ctx.fillStyle="rgba(125,211,252,.9)";
      ctx.fill();
    }

    if(clique.ativo && clique.x!==null){
      ctx.beginPath();
      ctx.arc(clique.x,clique.y,20+(1-clique.forca)*70,0,Math.PI*2);
      ctx.strokeStyle=`rgba(56,189,248,${clique.forca*.35})`;
      ctx.lineWidth=1.6;
      ctx.shadowColor="rgba(56,189,248,.8)";
      ctx.shadowBlur=12;
      ctx.stroke();
      ctx.shadowBlur=0;
    }

    requestAnimationFrame(animar);
  }

  animar();
}

