function calcularHistorico(tam,pass,D,valor){let p=new Array(tam).fill(0),centro=Math.floor(tam/2);p[centro]=valor;let h=[];for(let t=0;t<pass;t++){let np=[...p];for(let i=1;i<tam-1;i++)np[i]=p[i]+D*(p[i+1]-2*p[i]+p[i-1]);p=[...np];h.push([...p])}return h}

