function baixarCSV(){if(!tabelaBanco.length){alert("Inicie a simulação primeiro.");return}const linhas=["iteracao,pico,total,posicao_pico,centro,p25,p50,p75,ultimo"];tabelaBanco.forEach(r=>linhas.push([r.iteracao,r.pico,r.total,r.posicaoPico,r.centro,r.p25,r.p50,r.p75,r.ultimo].join(",")));const blob=new Blob([linhas.join("\n")],{type:"text/csv;charset=utf-8;"}),url=URL.createObjectURL(blob),a=document.createElement("a");a.href=url;a.download="resultados_iteracoes.csv";a.click();URL.revokeObjectURL(url)}

