function iniciarInteracao2D(){
  const canvas=document.getElementById("mapa2D");
  if(!canvas || canvas.dataset.interacao==="sim") return;

  canvas.dataset.interacao="sim";

  function atualizarPorMouse(e){
    const rect=canvas.getBoundingClientRect();
    const escalaX=canvas.width/rect.width;
    const escalaY=canvas.height/rect.height;
    const mx=(e.clientX-rect.left)*escalaX;
    const my=(e.clientY-rect.top)*escalaY;

    const cx=canvas.width*0.54;
    const cy=canvas.height*0.50;

    const dist=Math.hypot(mx-cx,my-cy);

    const novoRaio=Math.max(5,Math.min(120,Math.round(dist*0.22)));
    const novoEspalhamento=Math.max(10,Math.min(300,Math.round(dist)));

    const campoRaio=document.getElementById("raio2D");
    const campoEspalhamento=document.getElementById("espalhamento2D");

    if(campoRaio) campoRaio.value=novoRaio;
    if(campoEspalhamento) campoEspalhamento.value=novoEspalhamento;

    desenharMapa2D(tempo||0);
  }

  canvas.addEventListener("mousedown",(e)=>{
    estado2D.arrastando=true;
    canvas.style.cursor="grabbing";
    atualizarPorMouse(e);
  });

  window.addEventListener("mouseup",()=>{
    estado2D.arrastando=false;
    canvas.style.cursor="grab";
  });

  window.addEventListener("mousemove",(e)=>{
    if(!estado2D.arrastando) return;
    atualizarPorMouse(e);
  });

  canvas.style.cursor="grab";
}

function desenharMapa2D(frame){
  const canvas=document.getElementById("mapa2D");
  if(!canvas) return;

  iniciarInteracao2D();

  const ctx=canvas.getContext("2d");
  const w=canvas.width;
  const h=canvas.height;

  const valorInicial=parseFloat(document.getElementById("valor2D")?.value||100);
  const raioInicial=parseFloat(document.getElementById("raio2D")?.value||25);
  const espalhamento=parseFloat(document.getElementById("espalhamento2D")?.value||140);
  const velocidade=parseFloat(document.getElementById("velocidade2D")?.value||1.1);

  ctx.clearRect(0,0,w,h);

  const fundo=ctx.createLinearGradient(0,0,0,h);
  fundo.addColorStop(0,"#0f3f46");
  fundo.addColorStop(1,"#06111f");
  ctx.fillStyle=fundo;
  ctx.fillRect(0,0,w,h);

  // fundo sem mapa real: apenas textura discreta
  ctx.save();
  ctx.globalAlpha=0.18;
  ctx.strokeStyle="rgba(255,255,255,.18)";
  for(let x=-80;x<w+80;x+=60){
    ctx.beginPath();
    ctx.moveTo(x,0);
    ctx.lineTo(x+260,h);
    ctx.stroke();
  }
  ctx.restore();

  // molde didático inspirado em São Luís
  function pontoMapa(ang,escalaX,escalaY,irregular=1){
    const r=1+0.11*Math.sin(ang*3.2)+0.07*Math.cos(ang*5.7)+0.04*Math.sin(ang*9);
    return {
      x:w*0.52+Math.cos(ang)*escalaX*r*irregular,
      y:h*0.52+Math.sin(ang)*escalaY*r*irregular
    };
  }

  const pts=[];
  for(let i=0;i<180;i++){
    const ang=(Math.PI*2*i)/180;
    pts.push(pontoMapa(ang,w*0.33,h*0.27));
  }

  // sombra do bloco/ilha
  ctx.save();
  ctx.translate(16,18);
  ctx.beginPath();
  ctx.moveTo(pts[0].x,pts[0].y);
  for(const p of pts) ctx.lineTo(p.x,p.y);
  ctx.closePath();
  ctx.fillStyle="rgba(0,0,0,.36)";
  ctx.filter="blur(9px)";
  ctx.fill();
  ctx.restore();
  ctx.filter="none";

  // camada inferior para parecer bloco
  ctx.save();
  ctx.translate(10,12);
  ctx.beginPath();
  ctx.moveTo(pts[0].x,pts[0].y);
  for(const p of pts) ctx.lineTo(p.x,p.y);
  ctx.closePath();
  ctx.fillStyle="rgba(37,73,75,.95)";
  ctx.fill();
  ctx.restore();

  // ilha base branca
  ctx.beginPath();
  ctx.moveTo(pts[0].x,pts[0].y);
  for(const p of pts) ctx.lineTo(p.x,p.y);
  ctx.closePath();
  ctx.fillStyle="rgba(241,245,249,.94)";
  ctx.fill();
  ctx.strokeStyle="rgba(255,255,255,.92)";
  ctx.lineWidth=2;
  ctx.stroke();

  // linhas internas discretas
  ctx.save();
  ctx.clip();
  ctx.strokeStyle="rgba(100,116,139,.22)";
  ctx.lineWidth=1;
  for(let i=0;i<8;i++){
    ctx.beginPath();
    const y=h*0.34+i*24;
    ctx.moveTo(w*0.28,y);
    ctx.bezierCurveTo(w*0.42,y-25,w*0.55,y+28,w*0.76,y-8);
    ctx.stroke();
  }
  for(let i=0;i<6;i++){
    ctx.beginPath();
    const x=w*0.34+i*55;
    ctx.moveTo(x,h*0.27);
    ctx.bezierCurveTo(x+28,h*0.40,x-20,h*0.58,x+38,h*0.72);
    ctx.stroke();
  }
  ctx.restore();

  // clip para difusão só aparecer dentro da ilha
  ctx.save();
  ctx.beginPath();
  ctx.moveTo(pts[0].x,pts[0].y);
  for(const p of pts) ctx.lineTo(p.x,p.y);
  ctx.closePath();
  ctx.clip();

  const cx=w*0.54;
  const cy=h*0.50;
  const raio=raioInicial + frame*velocidade*0.65;
  const raioMax=Math.min(espalhamento+raioInicial,330);
  const raioAtual=Math.min(raio,raioMax);

  const grad=ctx.createRadialGradient(cx,cy,5,cx,cy,raioAtual);
  grad.addColorStop(0,"rgba(255,255,120,.92)");
  grad.addColorStop(0.25,"rgba(249,115,22,.62)");
  grad.addColorStop(0.58,"rgba(14,165,233,.34)");
  grad.addColorStop(1,"rgba(14,165,233,0)");

  ctx.fillStyle=grad;
  ctx.beginPath();
  ctx.arc(cx,cy,raioAtual,0,Math.PI*2);
  ctx.fill();

  ctx.beginPath();
  ctx.arc(cx,cy,raioAtual*0.82,0,Math.PI*2);
  ctx.strokeStyle="rgba(255,255,180,.72)";
  ctx.lineWidth=3;
  ctx.shadowColor="rgba(255,255,160,.9)";
  ctx.shadowBlur=14;
  ctx.stroke();
  ctx.shadowBlur=0;

  // números calculados dentro da ilha
  ctx.fillStyle="rgba(15,23,42,.55)";
  for(let i=0;i<26;i++){
    const ang=i*2.399;
    const rr=(i%8+2)/10;
    const px=cx+Math.cos(ang)*rr*220;
    const py=cy+Math.sin(ang)*rr*150;
    const d=Math.hypot(px-cx,py-cy);
    const intensidade=Math.max(0,1-d/(raioAtual||1));
    if(intensidade>0.05){
      ctx.fillStyle=`rgba(2,6,23,${0.15+intensidade*0.55})`;
      ctx.font="12px Arial";
      ctx.fillText((valorInicial*intensidade).toFixed(0),px,py);
    }
  }

  ctx.restore();

  // linha puxadora: muda os números e os números mudam a linha
  const distanciaPuxador=Math.min(330,Math.max(35,espalhamento));
  const angulo=-0.42;
  const hx=cx+Math.cos(angulo)*distanciaPuxador;
  const hy=cy+Math.sin(angulo)*distanciaPuxador;

  ctx.beginPath();
  ctx.moveTo(cx,cy);
  ctx.lineTo(hx,hy);
  ctx.strokeStyle="rgba(56,189,248,.85)";
  ctx.lineWidth=3;
  ctx.shadowColor="rgba(56,189,248,1)";
  ctx.shadowBlur=18;
  ctx.stroke();
  ctx.shadowBlur=0;

  ctx.beginPath();
  ctx.arc(hx,hy,12,0,Math.PI*2);
  ctx.fillStyle="#38bdf8";
  ctx.shadowColor="rgba(56,189,248,1)";
  ctx.shadowBlur=20;
  ctx.fill();
  ctx.shadowBlur=0;
  ctx.strokeStyle="white";
  ctx.lineWidth=2;
  ctx.stroke();

  ctx.fillStyle="#e0f2fe";
  ctx.font="20px Arial";
  ctx.fillText("Mapa 2D Interativo — Molde de São Luís",24,34);

  ctx.font="13px Arial";
  ctx.fillStyle="#bfdbfe";
  ctx.fillText(`Valor: ${valorInicial} | Raio: ${raioInicial} | Espalhamento: ${espalhamento} | Velocidade: ${velocidade}`,24,56);

  ctx.fillStyle="#ef4444";
  ctx.beginPath();
  ctx.arc(cx,cy,6,0,Math.PI*2);
  ctx.fill();

  ctx.fillStyle="#ffffff";
  ctx.font="13px Arial";
  ctx.fillText("ponto inicial",cx+12,cy-10);

  ctx.fillStyle="#dbeafe";
  ctx.font="13px Arial";
  ctx.fillText("arraste a bolinha azul para alterar raio/espalhamento",hx-120,hy-18);
}


function iniciarInteracao3D(){
  const canvas=document.getElementById("mapa3D");
  if(!canvas || canvas.dataset.interacao==="sim") return;

  canvas.dataset.interacao="sim";
  canvas.style.cursor="grab";

  function posicaoMouse(e){
    const rect=canvas.getBoundingClientRect();
    return {
      x:(e.clientX-rect.left)*(canvas.width/rect.width),
      y:(e.clientY-rect.top)*(canvas.height/rect.height)
    };
  }

  function atualizarPuxador3D(e){
    const pos=posicaoMouse(e);
    const cx=canvas.width*0.50;
    const cy=canvas.height*0.47;

    const dx=pos.x-cx;
    const dy=pos.y-cy;
    const dist=Math.sqrt(dx*dx+dy*dy);

    const novoEspalhamento=Math.max(10,Math.min(180,Math.round(dist*0.32)));
    const novaAltura=Math.max(10,Math.min(220,Math.round(40+Math.max(0,cy-pos.y)*0.55)));

    const campoEsp=document.getElementById("espalhamento3D");
    const campoAlt=document.getElementById("altura3D");

    if(campoEsp) campoEsp.value=novoEspalhamento;
    if(campoAlt) campoAlt.value=novaAltura;

    desenharMapa3D(tempo||0);
  }

  canvas.addEventListener("mousedown",(e)=>{
    const pos=posicaoMouse(e);

    if(estado3D.puxadorX!==null && estado3D.puxadorY!==null){
      const d=Math.hypot(pos.x-estado3D.puxadorX,pos.y-estado3D.puxadorY);

      if(d<26){
        estado3D.arrastandoPuxador=true;
        canvas.style.cursor="grabbing";
        atualizarPuxador3D(e);
        return;
      }
    }

    estado3D.arrastando=true;
    estado3D.ultimoX=e.clientX;
    estado3D.ultimoY=e.clientY;
    canvas.style.cursor="grabbing";
  });

  window.addEventListener("mouseup",()=>{
    estado3D.arrastando=false;
    estado3D.arrastandoPuxador=false;
    canvas.style.cursor="grab";
  });

  window.addEventListener("mousemove",(e)=>{
    if(estado3D.arrastandoPuxador){
      atualizarPuxador3D(e);
      return;
    }

    if(!estado3D.arrastando) return;

    const dx=e.clientX-estado3D.ultimoX;
    const dy=e.clientY-estado3D.ultimoY;

    estado3D.rotY += dx*0.008;
    estado3D.rotX += dy*0.006;

    estado3D.rotX=Math.max(-1.15,Math.min(-0.25,estado3D.rotX));

    estado3D.ultimoX=e.clientX;
    estado3D.ultimoY=e.clientY;

    desenharMapa3D(tempo||0);
  });

  ["valor3D","altura3D","espalhamento3D","velocidade3D"].forEach((id)=>{
    const el=document.getElementById(id);
    if(el){
      el.addEventListener("input",()=>desenharMapa3D(tempo||0));
    }
  });
}


function desenharMapa3D(frame){
  const canvas=document.getElementById("mapa3D");
  if(!canvas) return;

  iniciarInteracao3D();

  const ctx=canvas.getContext("2d");
  const w=canvas.width;
  const h=canvas.height;

  ctx.clearRect(0,0,w,h);

  const fundo=ctx.createLinearGradient(0,0,0,h);
  fundo.addColorStop(0,"#0b1f3a");
  fundo.addColorStop(1,"#020617");
  ctx.fillStyle=fundo;
  ctx.fillRect(0,0,w,h);

  const valorInicial3D=parseFloat(document.getElementById("valor3D")?.value||100);
  const altura=parseFloat(document.getElementById("altura3D")?.value||95);
  const espalhamento=parseFloat(document.getElementById("espalhamento3D")?.value||70);
  const velocidade=parseFloat(document.getElementById("velocidade3D")?.value||1.1);

  const cols=32;
  const rows=24;
  const escala=13;
  const espessura=70;

  const centroX=w*0.50;
  const centroY=h*0.47;

  function alturaDifusao(x,z){
    const dx=x-cols/2;
    const dz=z-rows/2;
    const dist=Math.sqrt(dx*dx+dz*dz);

    const raio=(frame*0.10*velocidade)%24;
    const onda=Math.exp(-Math.pow(dist-raio,2)/(espalhamento/12));
    const nucleo=Math.exp(-(dist*dist)/(espalhamento/2.8))*0.75;

    const escalaValor=Math.min(1.6,Math.max(0.35,Math.log10(valorInicial3D+10)/4));
    return Math.min(1,onda+nucleo)*altura*escalaValor;
  }

  function mascaraMapa(x,z){
    const nx=(x-cols/2)/(cols/2);
    const nz=(z-rows/2)/(rows/2);

    const forma=(nx*nx/0.92)+(nz*nz/0.62)+0.14*Math.sin(nx*7)-0.08*Math.cos(nz*8);
    const recorte=(nx<-0.72 && nz<-0.05) || (nx>0.75 && nz>0.18);

    return forma<1 && !recorte;
  }

  function projetar(x,y,z){
    const cx=x-cols/2;
    const cz=z-rows/2;

    let X=cx;
    let Y=y;
    let Z=cz;

    const cosY=Math.cos(estado3D.rotY);
    const sinY=Math.sin(estado3D.rotY);
    const x1=X*cosY-Z*sinY;
    const z1=X*sinY+Z*cosY;

    const cosX=Math.cos(estado3D.rotX);
    const sinX=Math.sin(estado3D.rotX);
    const y2=Y*cosX-z1*sinX;
    const z2=Y*sinX+z1*cosX;

    return {
      x:centroX+x1*escala,
      y:centroY+y2*escala,
      z:z2
    };
  }

  function corTopo(intensidade){
    const r=Math.floor(20+intensidade*230);
    const g=Math.floor(95+intensidade*150);
    const b=Math.floor(90-intensidade*45);
    return `rgb(${r},${g},${b})`;
  }

  function desenharPoligono(pontos,fill,stroke="rgba(255,255,255,.08)"){
    ctx.beginPath();
    ctx.moveTo(pontos[0].x,pontos[0].y);
    for(let i=1;i<pontos.length;i++){
      ctx.lineTo(pontos[i].x,pontos[i].y);
    }
    ctx.closePath();
    ctx.fillStyle=fill;
    ctx.fill();
    ctx.strokeStyle=stroke;
    ctx.lineWidth=0.6;
    ctx.stroke();
  }

  // sombra
  ctx.save();
  ctx.globalAlpha=0.25;
  ctx.fillStyle="#000";
  ctx.beginPath();
  ctx.ellipse(w/2,h*0.76,330,58,0,0,Math.PI*2);
  ctx.fill();
  ctx.restore();

  const faces=[];

  // Faces laterais do bloco
  for(let z=0;z<rows-1;z++){
    for(let x=0;x<cols-1;x++){
      if(!mascaraMapa(x,z)) continue;

      const h00=alturaDifusao(x,z)/escala;
      const h10=alturaDifusao(x+1,z)/escala;
      const h01=alturaDifusao(x,z+1)/escala;
      const h11=alturaDifusao(x+1,z+1)/escala;

      const media=(h00+h10+h01+h11)/(altura/escala*4);

      const p1=projetar(x,-h00,z);
      const p2=projetar(x+1,-h10,z);
      const p3=projetar(x+1,-h11,z+1);
      const p4=projetar(x,-h01,z+1);

      faces.push({
        z:(p1.z+p2.z+p3.z+p4.z)/4,
        pontos:[p1,p2,p3,p4],
        fill:corTopo(media),
        stroke:media>0.18?"rgba(255,255,255,.16)":"rgba(255,255,255,.05)"
      });

      // bordas laterais para parecer bloco
      if(!mascaraMapa(x,z+1)){
        const b1=projetar(x,-h01,z+1);
        const b2=projetar(x+1,-h11,z+1);
        const b3=projetar(x+1,espessura/escala,z+1);
        const b4=projetar(x,espessura/escala,z+1);
        faces.push({z:(b1.z+b2.z+b3.z+b4.z)/4,pontos:[b1,b2,b3,b4],fill:"rgb(25,62,68)",stroke:"rgba(0,0,0,.18)"});
      }

      if(!mascaraMapa(x+1,z)){
        const b1=projetar(x+1,-h10,z);
        const b2=projetar(x+1,-h11,z+1);
        const b3=projetar(x+1,espessura/escala,z+1);
        const b4=projetar(x+1,espessura/escala,z);
        faces.push({z:(b1.z+b2.z+b3.z+b4.z)/4,pontos:[b1,b2,b3,b4],fill:"rgb(18,50,58)",stroke:"rgba(0,0,0,.18)"});
      }

      if(!mascaraMapa(x-1,z)){
        const b1=projetar(x,-h00,z);
        const b2=projetar(x,-h01,z+1);
        const b3=projetar(x,espessura/escala,z+1);
        const b4=projetar(x,espessura/escala,z);
        faces.push({z:(b1.z+b2.z+b3.z+b4.z)/4,pontos:[b1,b2,b3,b4],fill:"rgb(15,45,54)",stroke:"rgba(0,0,0,.18)"});
      }

      if(!mascaraMapa(x,z-1)){
        const b1=projetar(x,-h00,z);
        const b2=projetar(x+1,-h10,z);
        const b3=projetar(x+1,espessura/escala,z);
        const b4=projetar(x,espessura/escala,z);
        faces.push({z:(b1.z+b2.z+b3.z+b4.z)/4,pontos:[b1,b2,b3,b4],fill:"rgb(30,78,74)",stroke:"rgba(0,0,0,.18)"});
      }
    }
  }

  faces.sort((a,b)=>a.z-b.z);

  for(const f of faces){
    desenharPoligono(f.pontos,f.fill,f.stroke);
  }

  // linhas de brilho no pico da difusão
  const raio=(frame*0.10*velocidade)%24;
  ctx.save();
  ctx.globalCompositeOperation="screen";
  for(let z=1;z<rows-1;z++){
    for(let x=1;x<cols-1;x++){
      if(!mascaraMapa(x,z)) continue;

      const dx=x-cols/2;
      const dz=z-rows/2;
      const dist=Math.sqrt(dx*dx+dz*dz);

      if(Math.abs(dist-raio)<0.8){
        const p=projetar(x,-alturaDifusao(x,z)/escala,z);
        ctx.fillStyle="rgba(255,245,120,.65)";
        ctx.shadowColor="rgba(255,245,120,.95)";
        ctx.shadowBlur=12;
        ctx.beginPath();
        ctx.arc(p.x,p.y,2.2,0,Math.PI*2);
        ctx.fill();
      }
    }
  }
  ctx.restore();
  ctx.shadowBlur=0;

  
  // linha puxadora 3D: altera altura e espalhamento
  const centroPuxador=projetar(cols/2,-alturaDifusao(cols/2,rows/2)/escala,rows/2);
  const distanciaPuxador=Math.min(260,Math.max(55,espalhamento*1.45));
  const alturaVisual=Math.min(170,Math.max(35,altura*0.75));

  const puxadorX=centroPuxador.x + distanciaPuxador*Math.cos(-0.38);
  const puxadorY=centroPuxador.y + distanciaPuxador*Math.sin(-0.38) - alturaVisual*0.35;

  estado3D.puxadorX=puxadorX;
  estado3D.puxadorY=puxadorY;

  ctx.beginPath();
  ctx.moveTo(centroPuxador.x,centroPuxador.y);
  ctx.lineTo(puxadorX,puxadorY);
  ctx.strokeStyle="rgba(56,189,248,.92)";
  ctx.lineWidth=3;
  ctx.shadowColor="rgba(56,189,248,1)";
  ctx.shadowBlur=18;
  ctx.stroke();
  ctx.shadowBlur=0;

  ctx.beginPath();
  ctx.arc(puxadorX,puxadorY,13,0,Math.PI*2);
  ctx.fillStyle="#38bdf8";
  ctx.shadowColor="rgba(56,189,248,1)";
  ctx.shadowBlur=24;
  ctx.fill();
  ctx.shadowBlur=0;
  ctx.strokeStyle="white";
  ctx.lineWidth=2;
  ctx.stroke();

  ctx.fillStyle="#dbeafe";
  ctx.font="13px Arial";
  ctx.fillText("arraste a bolinha azul para alterar altura/espalhamento",puxadorX-175,puxadorY-20);

ctx.fillStyle="#e0f2fe";
  ctx.font="20px Arial";
  ctx.fillText("Mapa 3D Interativo — bloco didático de São Luís",24,34);

  ctx.font="13px Arial";
  ctx.fillStyle="#bfdbfe";
  ctx.fillText("Arraste para girar • Altura = concentração • Cor = intensidade da difusão",24,56);
  ctx.fillText(`Valor 3D: ${valorInicial3D} | Altura: ${altura} | Espalhamento: ${espalhamento} | Velocidade: ${velocidade}`,24,76);

  ctx.fillStyle="rgba(15,23,42,.72)";
  ctx.fillRect(w-250,h-96,222,72);
  ctx.strokeStyle="rgba(125,211,252,.35)";
  ctx.strokeRect(w-250,h-96,222,72);

  ctx.fillStyle="#e0f2fe";
  ctx.font="13px Arial";
  ctx.fillText("Controles:",w-232,h-72);
  ctx.fillText("altura, espalhamento e velocidade",w-232,h-50);
  ctx.fillText("alteram a propagação em tempo real",w-232,h-30);
}


function iniciarSimulacao(){const tam=parseInt(tamanho.value),pass=parseInt(passos.value),D=parseFloat(difusao.value),valor=parseFloat(populacaoInicial.value),tipo=tipoSimulacao.value,cenario=cenarioReal.value,modo=modoVisual.value;if(D<=0||D>.5){alert("Use D entre 0.01 e 0.50.");return}if(tam<20||pass<20||valor<=0){alert("Use valores maiores.");return}if(animacao)clearInterval(animacao);configAtual={tamanho:tam,passos:pass,D,valorInicial:valor,tipo,modoVisual:modo,cenario};historicoGlobal=calcularHistorico(tam,pass,D,valor);gerarBancoDeDados(historicoGlobal);tempo=0;pausado=false;criarGrafico(Array.from({length:tam},(_,i)=>i),historicoGlobal[0],valor,modo,tipo);desenharMapaCalor(historicoGlobal,0,valor);desenharMapa2D(0);desenharMapa3D(0);atualizarEstatisticas(historicoGlobal[0],0);rodarAnimacao()}

function rodarAnimacao(){if(animacao)clearInterval(animacao);const vel=parseInt(velocidade.value);animacao=setInterval(()=>{if(pausado)return;if(tempo>=configAtual.passos){clearInterval(animacao);return}const dados=historicoGlobal[tempo];grafico.data.datasets[0].data=dados;grafico.update();tempoAtual.innerText=`2. Tempo: ${tempo}`;let msg=mensagemPorTempo(tempo,configAtual.passos,configAtual.tipo);if(configAtual.cenario==="saoluis")msg+=" O mapa 2D mostra uma camada didática de difusão sobre São Luís.";if(configAtual.cenario==="uema")msg+=" Esse exemplo pode representar circulação de estudantes entre setores ou campi.";mensagemDidatica.innerText=msg;atualizarEstatisticas(dados,tempo);desenharMapaCalor(historicoGlobal,tempo,configAtual.valorInicial);desenharMapa2D(tempo);desenharMapa3D(tempo);tempo++},vel)}

function pausarSimulacao(){pausado=true;mensagemDidatica.innerText="A simulação foi pausada. Observe o formato atual da distribuição."}
function continuarSimulacao(){pausado=false;rodarAnimacao()}
function reiniciarSimulacao(){iniciarSimulacao()}
velocidade.addEventListener("input",()=>{if(historicoGlobal.length>0&&!pausado)rodarAnimacao()});
mapaImagem.onload=()=>desenharMapa2D(0);

function animarAplicacoes(){
  const social = document.getElementById("animRedeSocial");
  const clima = document.getElementById("animPrevisaoTempo");
  if(!social || !clima) return;

  const sctx = social.getContext("2d");
  const cctx = clima.getContext("2d");

  let pessoas = [];
  let gotas = [];
  let nuvens = [];

  function getValor(id, fallback){
    const el = document.getElementById(id);
    return el ? parseFloat(el.value) : fallback;
  }

  function recriarPessoas(){
    const quantidade = Math.floor(getValor("socialPontos",24));
    pessoas = Array.from({length:quantidade},(_,i)=>({
      x:70 + Math.random()*380,
      y:55 + Math.random()*130,
      r:7 + Math.random()*4,
      ativo:i===0,
      fase:Math.random()*Math.PI*2,
      algoritmo:Math.random()
    }));
    pessoas[0].x = social.width/2;
    pessoas[0].y = social.height/2;
    pessoas[0].algoritmo = 1;
  }

  function recriarClima(){
    nuvens = Array.from({length:6},()=>({
      x:Math.random()*clima.width,
      y:35+Math.random()*60,
      v:.25+Math.random()*.35,
      s:.75+Math.random()*.6
    }));

    gotas = Array.from({length:80},()=>({
      x:Math.random()*clima.width,
      y:Math.random()*clima.height,
      v:1+Math.random()*2.2
    }));
  }

  recriarPessoas();
  recriarClima();

  const socialPontos = document.getElementById("socialPontos");
  if(socialPontos){
    socialPontos.addEventListener("input", recriarPessoas);
  }

  function desenharSocial(t){
    const velocidade = getValor("socialVelocidade",1.4);
    const alcance = getValor("socialAlcance",125);

    sctx.clearRect(0,0,social.width,social.height);

    const tempoLocal = ((t/60)*velocidade)%pessoas.length;
    pessoas.forEach((p,i)=> p.ativo = i <= tempoLocal || p.algoritmo > .92 && i < tempoLocal + 4);

    // ondas do algoritmo
    const cx = social.width/2;
    const cy = social.height/2;
    for(let k=0;k<3;k++){
      const raio = ((t*velocidade*0.8 + k*70) % 210);
      sctx.beginPath();
      sctx.arc(cx,cy,raio,0,Math.PI*2);
      sctx.strokeStyle=`rgba(56,189,248,${0.18-k*0.04})`;
      sctx.lineWidth=2;
      sctx.stroke();
    }

    for(let i=0;i<pessoas.length;i++){
      for(let j=i+1;j<pessoas.length;j++){
        const a=pessoas[i], b=pessoas[j];
        const dx=a.x-b.x, dy=a.y-b.y;
        const dist=Math.sqrt(dx*dx+dy*dy);
        const pesoAlgoritmo = (a.algoritmo+b.algoritmo)/2;
        const limite = alcance + pesoAlgoritmo*35;

        if(dist<limite && (a.ativo || b.ativo)){
          sctx.strokeStyle = a.ativo && b.ativo ? "rgba(56,189,248,.62)" : "rgba(148,163,184,.18)";
          sctx.lineWidth = a.ativo && b.ativo ? 2.2 : 1;
          sctx.beginPath();
          sctx.moveTo(a.x,a.y);
          sctx.lineTo(b.x,b.y);
          sctx.stroke();
        }
      }
    }

    pessoas.forEach((p,i)=>{
      const pulso = p.ativo ? Math.sin(t/12+p.fase)*2 : 0;
      const destaque = p.algoritmo > .82;

      sctx.beginPath();
      sctx.arc(p.x,p.y,p.r+pulso+(destaque?2:0),0,Math.PI*2);
      sctx.fillStyle = p.ativo ? (destaque ? "#facc15" : "#38bdf8") : "rgba(148,163,184,.35)";
      sctx.fill();
      sctx.strokeStyle = p.ativo ? "rgba(255,255,255,.85)" : "rgba(255,255,255,.18)";
      sctx.stroke();

      if(p.ativo){
        sctx.beginPath();
        sctx.arc(p.x,p.y,p.r+10+Math.sin(t/10+p.fase)*5,0,Math.PI*2);
        sctx.strokeStyle=destaque ? "rgba(250,204,21,.24)" : "rgba(56,189,248,.18)";
        sctx.stroke();
      }
    });

    sctx.fillStyle="#dbeafe";
    sctx.font="13px Arial";
    sctx.fillText("perfis + conexões + recomendação algorítmica",18,210);

    sctx.fillStyle="rgba(250,204,21,.95)";
    sctx.fillText("amarelo = perfil impulsionado pelo algoritmo",18,190);
  }

  function desenharNuvem(ctx,x,y,s){
    ctx.fillStyle="rgba(226,232,240,.9)";
    ctx.beginPath();
    ctx.arc(x,y,18*s,0,Math.PI*2);
    ctx.arc(x+20*s,y-8*s,24*s,0,Math.PI*2);
    ctx.arc(x+45*s,y,18*s,0,Math.PI*2);
    ctx.rect(x-5*s,y,60*s,18*s);
    ctx.fill();
  }

  function desenharClima(t){
    const velocidade = getValor("climaVelocidade",1.2);
    const intensidade = getValor("climaIntensidade",1.2);
    const qtdChuva = Math.floor(getValor("climaChuva",36));

    cctx.clearRect(0,0,clima.width,clima.height);

    const grad=cctx.createLinearGradient(0,0,0,clima.height);
    grad.addColorStop(0,"rgba(14,165,233,.20)");
    grad.addColorStop(1,"rgba(2,6,23,.05)");
    cctx.fillStyle=grad;
    cctx.fillRect(0,0,clima.width,clima.height);

    const cols=10, rows=5;
    const cw=clima.width/cols, ch=clima.height/rows;

    for(let y=0;y<rows;y++){
      for(let x=0;x<cols;x++){
        const onda = (Math.sin((t*velocidade)/35+x*.7+y*.9)+1)/2;
        const val = Math.min(onda*intensidade,1);
        cctx.fillStyle=`rgba(${Math.floor(40+val*215)},${Math.floor(120+val*90)},${Math.floor(255-val*180)},.32)`;
        cctx.fillRect(x*cw,y*ch,cw-2,ch-2);

        cctx.strokeStyle="rgba(255,255,255,.08)";
        cctx.strokeRect(x*cw,y*ch,cw-2,ch-2);

        if(val>.75){
          cctx.fillStyle="rgba(255,255,255,.75)";
          cctx.font="11px Arial";
          cctx.fillText("quente",x*cw+8,y*ch+18);
        }
      }
    }

    nuvens.forEach(n=>{
      n.x+=n.v*velocidade;
      if(n.x>clima.width+80)n.x=-90;
      desenharNuvem(cctx,n.x,n.y,n.s);
    });

    for(let i=0;i<qtdChuva && i<gotas.length;i++){
      const g = gotas[i];
      g.y+=g.v*velocidade;
      if(g.y>clima.height){g.y=90;g.x=Math.random()*clima.width;}
      cctx.strokeStyle="rgba(125,211,252,.78)";
      cctx.beginPath();
      cctx.moveTo(g.x,g.y);
      cctx.lineTo(g.x-3,g.y+9);
      cctx.stroke();
    }

    // setas de vento
    for(let i=0;i<6;i++){
      const x = 40+i*75;
      const y = 150 + Math.sin(t/25+i)*8;
      cctx.strokeStyle="rgba(255,255,255,.38)";
      cctx.lineWidth=2;
      cctx.beginPath();
      cctx.moveTo(x,y);
      cctx.lineTo(x+35,y);
      cctx.lineTo(x+27,y-7);
      cctx.moveTo(x+35,y);
      cctx.lineTo(x+27,y+7);
      cctx.stroke();
    }

    cctx.fillStyle="#dbeafe";
    cctx.font="13px Arial";
    cctx.fillText("células: temperatura | gotas: umidade | setas: vento",18,210);
  }

  function loop(t){
    desenharSocial(t);
    desenharClima(t);
    requestAnimationFrame(loop);
  }

  requestAnimationFrame(loop);
}




