function abrirCNA(){
  const egg=document.getElementById("easterEggCNA");
  if(!egg) return;

  prepararTextoCNA();
  egg.classList.add("ativo");

  if(window.MathJax){
    MathJax.typesetPromise();
  }
}

function fecharCNA(){
  const egg=document.getElementById("easterEggCNA");
  if(!egg) return;
  egg.classList.remove("ativo");
}

document.addEventListener("keydown",(e)=>{
  if(e.key==="Escape") fecharCNA();
});

document.addEventListener("click",(e)=>{
  const egg=document.getElementById("easterEggCNA");
  if(egg && e.target.id==="easterEggCNA"){
    fecharCNA();
  }
});

prepararTextoCNA();

iniciarParticulas();animarAplicacoes();iniciarSimulacao();


